class Solution:
    def possibleBipartition(self, n: int, dislikes: List[List[int]]) -> bool:
        graph = [[False] * (n + 1) for _ in range(n)]
        for a, b in dislikes:
            graph[a][b] = True
            graph[b][a] = True
        return max_degree(graph) == n // 2

def max_degree(graph):
    degree = [0] * (n + 1)
    for i in range(n):
        for j in graph[i]:
            degree[j] += 1
    for i in range(n):
        for j in range(n):
            if graph[i][j]:
                degree[i] += degree[j]
    return max(degree)

